export const AuditProvider = ({ children }: React.PropsWithChildren<{}>) => {
    // --- STATE ---
    const [customStandards, setCustomStandards] = useState<StandardsData>({});
    const [standardKey, setStandardKey] = useState<string>("");
    const [auditInfo, setAuditInfo] = useState<AuditInfo>(DEFAULT_AUDIT_INFO);
    const [privacySettings, setPrivacySettings] = useState<PrivacySettings>(DEFAULT_PRIVACY);

    // Dynamic Audit Types
    const [auditTypeOptions, setAuditTypeOptions] = useState<Record<string, string>>(DEFAULT_AUDIT_TYPES);

    // Processes (Start Empty)
    const [processes, setProcesses] = useState<AuditProcess[]>([]);
    const [activeProcessId, setActiveProcessId] = useState<string | null>(null);

    // Smart Planning State
    const [auditSites, setAuditSites] = useState<AuditSite[]>([]);
    const [auditTeam, setAuditTeam] = useState<AuditMember[]>([]);
    const [auditPlanConfig, setAuditPlanConfig] = useState<AuditPlanConfig>(DEFAULT_PLAN_CONFIG);
    const [auditSchedule, setAuditSchedule] = useState<AuditScheduleItem[]>([]);

    // Active View Data
    const [loadedProcessId, setLoadedProcessId] = useState<string | null>(null);
    const [evidence, setEvidence] = useState(INITIAL_EVIDENCE);
    const [matrixData, setMatrixData] = useState<Record<string, MatrixRow[]>>({});
    const [evidenceTags, setEvidenceTags] = useState<EvidenceTag[]>([]);

    const [selectedClauses, setSelectedClauses] = useState<string[]>([]);

    // KB
    const [knowledgeBase, setKnowledgeBase] = useState<string | null>(null);
    const [knowledgeFileName, setKnowledgeFileName] = useState<string | null>(null);

    // Analysis
    const [analysisResult, setAnalysisResult] = useState<AnalysisResult[] | null>(null);
    const [selectedFindings, setSelectedFindings] = useState<Record<string, boolean>>({});
    const [finalReportText, setFinalReportText] = useState<string | null>(null);

    // Job Management
    const [currentJobId, setCurrentJobId] = useState<string | null>(null);

    const standards = useMemo(() => ({ ...STANDARDS_DATA, ...customStandards }), [customStandards]);
    const activeProcess = useMemo(() => processes.find(p => p.id === activeProcessId), [processes, activeProcessId]);
    const processesRef = useRef(processes);
    useEffect(() => { processesRef.current = processes; }, [processes]);

    // --- INIT AUDIT TYPES ---
    useEffect(() => {
        const savedTypes = localStorage.getItem("iso_audit_types_config");
        if (savedTypes) {
            try {
                setAuditTypeOptions(JSON.parse(savedTypes));
            } catch (e) {
                console.error("Failed to load audit types config", e);
            }
        }
    }, []);

    // --- SYNC EFFECTS ---
    useEffect(() => {
        if (!activeProcessId) {
            setEvidence("");
            setMatrixData({});
            setEvidenceTags([]);
            setLoadedProcessId(null);
            return;
        }
        if (activeProcessId === loadedProcessId) return;

        const target = processesRef.current.find(p => p.id === activeProcessId);
        if (target) {
            setEvidence(target.evidence || "");
            setMatrixData(target.matrixData || {});
            setEvidenceTags(target.evidenceTags || []);
            setLoadedProcessId(activeProcessId);
        } else {
            setLoadedProcessId(null);
        }
    }, [activeProcessId, loadedProcessId]); 

    useEffect(() => {
        if (!loadedProcessId) return;
        setProcesses(prev => prev.map(p => {
            if (p.id === loadedProcessId) {
                if (p.evidence !== evidence || p.matrixData !== matrixData || p.evidenceTags !== evidenceTags) {
                    return { ...p, evidence, matrixData, evidenceTags };
                }
            }
            return p;
        }));
    }, [evidence, matrixData, evidenceTags, loadedProcessId]);

    // --- NEW: INTELLIGENT SYNC (Sites & Staff) ---
    // Mirrors the logic: Total must reflect reality of Planning allocations.
    useEffect(() => {
        const allocatedEmployees = auditSites.reduce((sum, s) => sum + (s.employeeCount || 0), 0);

        setAuditInfo(prev => {
            let next = { ...prev };
            let hasChange = false;

            // 1. Sync Total Sites Count (Strict Equality)
            if (prev.totalSites !== auditSites.length) {
                next.totalSites = auditSites.length;
                hasChange = true;
            }

            // 2. Sync Total Staff (Floor Constraint: Cap cannot be less than allocated)
            // Allows user to set buffer in Sidebar, but auto-expands if Planning needs more.
            const currentCap = prev.totalEmployees || 0;
            if (allocatedEmployees > currentCap) {
                next.totalEmployees = allocatedEmployees;
                hasChange = true;
            }

            return hasChange ? next : prev;
        });
    }, [auditSites, auditInfo.totalEmployees, auditInfo.totalSites]);

    // --- ACTIONS ---
    const addCustomStandard = (key: string, std: Standard) => {
        setCustomStandards(prev => ({ ...prev, [key]: std }));
    };

    const updateStandard = (std: Standard) => {
        setCustomStandards(prev => ({ ...prev, [standardKey]: std }));
    };

    const resetStandard = (key: string) => {
        setCustomStandards(prev => {
            const next = { ...prev };
            delete next[key];
            return next;
        });
        if (standardKey === key) setStandardKey("");
    };

    // AUDIT TYPE MANAGEMENT
    const addAuditType = (type: string, objective: string) => {
        setAuditTypeOptions(prev => {
            const next = { ...prev, [type]: objective };
            localStorage.setItem("iso_audit_types_config", JSON.stringify(next));
            return next;
        });
    };

    const deleteAuditType = (type: string) => {
        setAuditTypeOptions(prev => {
            const next = { ...prev };
            delete next[type];
            localStorage.setItem("iso_audit_types_config", JSON.stringify(next));
            return next;
        });
    };

    const resetAuditTypes = () => {
        setAuditTypeOptions(DEFAULT_AUDIT_TYPES);
        localStorage.removeItem("iso_audit_types_config");
    };

    const addProcess = (name: string) => {
        const newId = `proc_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`;
        const newProcess = { 
            id: newId, 
            name, 
            evidence: "", 
            interviewees: [],
            matrixData: {}, 
            evidenceTags: [], 
            uploadedFiles: [],
            siteIds: []
        };
        setProcesses(prev => [...prev, newProcess]);
        setActiveProcessId(newId);
    };

    const renameProcess = (id: string, name: string) => {
        setProcesses(prev => prev.map(p => p.id === id ? { ...p, name } : p));
    };

    const updateProcessCode = (id: string, code: string) => {
        setProcesses(prev => prev.map(p => p.id === id ? { ...p, competencyCode: code } : p));
    };

    const updateProcessSites = (id: string, siteIds: string[]) => {
        setProcesses(prev => prev.map(p => p.id === id ? { ...p, siteIds } : p));
    };

    const deleteProcess = (idToDelete: string) => {
        if (activeProcessId === idToDelete) {
            setProcesses(prev => {
                const remaining = prev.filter(p => p.id !== idToDelete);
                const nextId = remaining.length > 0 ? remaining[0].id : null;
                setActiveProcessId(nextId);
                return remaining;
            });
        } else {
            setProcesses(prev => prev.filter(p => p.id !== idToDelete));
        }
    };

    const findClauseInStandard = (cid: string, standard: Standard | undefined): any => {
        if (!standard) return null;
        const allClauses = standard.groups.flatMap(g => g.clauses);
        const findRecursive = (id: string, list: any[]): any => {
            for (const c of list) {
                if (c.id === id) return c;
                if (c.subClauses) {
                    const found = findRecursive(id, c.subClauses);
                    if (found) return found;
                }
            }
            return null;
        };
        return findRecursive(cid, allClauses);
    };

    const batchUpdateProcessClauses = (updates: { processId: string, clauses: string[] }[]) => {
        setProcesses(prev => prev.map(p => {
            const update = updates.find(u => u.processId === p.id);
            if (update) {
                const newMatrixData = { ...p.matrixData };
                const standard = standards[standardKey];

                update.clauses.forEach(clauseId => {
                    if (!newMatrixData[clauseId]) {
                        const clause = findClauseInStandard(clauseId, standard);
                        const desc = clause?.description || "Requirement";
                        newMatrixData[clauseId] = [{
                            id: `${clauseId}_req_0`,
                            requirement: desc,
                            evidenceInput: "",
                            status: 'pending'
                        }];
                    }
                });
                return { ...p, matrixData: newMatrixData };
            }
            return p;
        }));

        const activeUpdate = updates.find(u => u.processId === loadedProcessId);
        if (activeUpdate) {
             setMatrixData(prev => {
                 const next = { ...prev };
                 const standard = standards[standardKey];
                 activeUpdate.clauses.forEach(cid => {
                     if(!next[cid]) {
                         const c = findClauseInStandard(cid, standard);
                         const desc = c?.description || "Requirement";
                         next[cid] = [{ id: `${cid}_req_0`, requirement: desc, evidenceInput: "", status: 'pending' }];
                     }
                 });
                 return next;
             });
        }
    };

    const toggleProcessClause = (processId: string, clauseId: string) => {
        setProcesses(prev => prev.map(p => {
            if (p.id !== processId) return p;
            const newMatrixData = { ...p.matrixData };
            if (newMatrixData[clauseId]) {
                delete newMatrixData[clauseId];
            } else {
                const standard = standards[standardKey];
                const clause = findClauseInStandard(clauseId, standard);
                const desc = clause?.description || "Requirement";
                newMatrixData[clauseId] = [{
                    id: `${clauseId}_req_0`,
                    requirement: desc,
                    evidenceInput: "",
                    status: 'pending'
                }];
            }
            return { ...p, matrixData: newMatrixData };
        }));

        if (loadedProcessId === processId) {
            setMatrixData(prev => {
                const next = { ...prev };
                if (next[clauseId]) {
                    delete next[clauseId];
                } else {
                    const standard = standards[standardKey];
                    const clause = findClauseInStandard(clauseId, standard);
                    const desc = clause?.description || "Requirement";
                    next[clauseId] = [{
                        id: `${clauseId}_req_0`,
                        requirement: desc,
                        evidenceInput: "",
                        status: 'pending'
                    }];
                }
                return next;
            });
        }
    };

    const addInterviewee = (name: string) => {
        setProcesses(prev => prev.map(p => {
            if (p.id === activeProcessId) {
                if (!p.interviewees.includes(name)) {
                    return { ...p, interviewees: [...p.interviewees, name] };
                }
            }
            return p;
        }));
    };

    const removeInterviewee = (name: string) => {
        setProcesses(prev => prev.map(p => {
            if (p.id === activeProcessId) {
                return { ...p, interviewees: p.interviewees.filter(i => i !== name) };
            }
            return p;
        }));
    };

    const addEvidenceTag = (tag: EvidenceTag) => {
        setEvidenceTags(prev => [...prev, tag]);
    };

    const loadKnowledgeForStandard = async (key: string) => {
        try {
            const doc = await KnowledgeStore.getDocument(key);
            if (doc) {
                setKnowledgeBase(doc.content);
                setKnowledgeFileName(doc.fileName);
            } else {
                setKnowledgeBase(null);
                setKnowledgeFileName(null);
            }
        } catch (e) { console.error(e); }
    };

    const clearKnowledge = async () => {
        setKnowledgeBase(null);
        setKnowledgeFileName(null);
        if (standardKey) {
            await KnowledgeStore.deleteStandardData(standardKey);
        }
    };

    const setKnowledgeData = (content: string, fileName: string) => {
        setKnowledgeBase(content);
        setKnowledgeFileName(fileName);
    };

    // --- JOB MANAGEMENT LOGIC ---
    const saveCurrentJob = async (name: string) => {
        // Prepare Snapshot
        const data = {
            standardKey, auditInfo, selectedClauses, privacySettings,
            activeProcessId, processes, auditSites, auditTeam, auditPlanConfig, auditSchedule,
            analysisResult, selectedFindings, finalReportText
        };

        // Calculate progress stats
        const totalFindings = analysisResult ? analysisResult.length : 0;
        let progress = 0;
        if (processes.length > 0) {
            let totalClauses = 0;
            let plannedClauses = 0;
            // Simple heuristic: Count processes * clauses mapped
            processes.forEach(p => {
                const keys = Object.keys(p.matrixData);
                plannedClauses += keys.length;
            });
            // Total would be approx number of clauses in standard * processes, but for now just use filled rows
            // Let's refine: Progress = (Clauses with Evidence / Total Mapped Clauses) * 100
            let filledClauses = 0;
            processes.forEach(p => {
                Object.values(p.matrixData).forEach(rows => {
                    if (rows.some(r => r.status === 'supplied')) filledClauses++;
                });
            });
            progress = plannedClauses > 0 ? Math.round((filledClauses / plannedClauses) * 100) : 0;
        }

        const job: AuditJob = {
            id: currentJobId || `job_${Date.now()}`,
            name,
            lastModified: Date.now(),
            createdDate: currentJobId ? Date.now() : Date.now(), // Rough approx if updating
            status: finalReportText ? 'Completed' : 'In Progress',
            thumbnailStats: {
                company: auditInfo.company || "Untitled",
                standard: standards[standardKey]?.name || "No Standard",
                progress,
                findingsCount: totalFindings
            },
            data
        };

        await JobStore.saveJob(job);
        setCurrentJobId(job.id);
    };

    const loadJob = (job: AuditJob) => {
        restoreSession(job.data);
        setCurrentJobId(job.id);
    };

    const resetSession = () => {
        setCurrentJobId(null);
        setStandardKey("");
        setAuditInfo(DEFAULT_AUDIT_INFO);
        setProcesses([]);
        setActiveProcessId(null);
        setLoadedProcessId(null); 
        setEvidence("");
        setMatrixData({});
        setEvidenceTags([]);
        setSelectedClauses([]);
        setAnalysisResult(null);
        setSelectedFindings({});
        setFinalReportText(null);
        setKnowledgeBase(null);
        setKnowledgeFileName(null);
        setPrivacySettings(DEFAULT_PRIVACY);
        // Reset Smart Planning
        setAuditSites([]);
        setAuditTeam([]);
        setAuditSchedule([]);
        setAuditPlanConfig(DEFAULT_PLAN_CONFIG);
    };

    const restoreSession = (data: any) => {
        if (data.standardKey) setStandardKey(data.standardKey);
        if (data.auditInfo) setAuditInfo({ ...DEFAULT_AUDIT_INFO, ...data.auditInfo });
        if (data.selectedClauses) setSelectedClauses(data.selectedClauses);
        if (data.privacySettings) setPrivacySettings(data.privacySettings);

        if (data.processes && data.processes.length > 0) {
            setProcesses(data.processes);
            if(data.activeProcessId) setActiveProcessId(data.activeProcessId);
        } else if (data.scopes && data.scopes.length > 0) {
             const migrated = data.scopes.map((s: any) => ({
                 ...s,
                 interviewees: [] 
             }));
             setProcesses(migrated);
             if(data.activeScopeId) setActiveProcessId(data.activeScopeId);
        }

        if (data.analysisResult) setAnalysisResult(data.analysisResult);
        if (data.selectedFindings) setSelectedFindings(data.selectedFindings);
        if (data.finalReportText) setFinalReportText(data.finalReportText);

        if (data.auditSites) setAuditSites(data.auditSites);
        if (data.auditTeam) setAuditTeam(data.auditTeam);

        // SAFE RESTORE: MERGE WITH DEFAULT TO PREVENT UNDEFINED ARRAYS
        if (data.auditPlanConfig) {
            setAuditPlanConfig({
                ...DEFAULT_PLAN_CONFIG,
                ...data.auditPlanConfig,
                auditDates: data.auditPlanConfig.auditDates || DEFAULT_PLAN_CONFIG.auditDates
            });
        }

        if (data.auditSchedule) setAuditSchedule(data.auditSchedule);

        if(data.standardKey) loadKnowledgeForStandard(data.standardKey);
    };

    const contextValue = useMemo(() => ({
        standards, standardKey, setStandardKey, customStandards, addCustomStandard, updateStandard, resetStandard,
        auditInfo, setAuditInfo,
        privacySettings, setPrivacySettings,
        auditTypeOptions, addAuditType, deleteAuditType, resetAuditTypes,
        processes, activeProcessId, activeProcess, setActiveProcessId, addProcess, renameProcess, updateProcessCode, updateProcessSites, deleteProcess, batchUpdateProcessClauses, toggleProcessClause,
        addInterviewee, removeInterviewee,
        auditSites, setAuditSites, auditTeam, setAuditTeam, auditPlanConfig, setAuditPlanConfig, auditSchedule, setAuditSchedule,
        evidence, setEvidence, matrixData, setMatrixData, evidenceTags, addEvidenceTag,
        selectedClauses, setSelectedClauses,
        knowledgeBase, knowledgeFileName, loadKnowledgeForStandard, clearKnowledge, setKnowledgeData,
        analysisResult, setAnalysisResult, selectedFindings, setSelectedFindings, finalReportText, setFinalReportText,
        resetSession, restoreSession,
        currentJobId, saveCurrentJob, loadJob
    }), [
        standards, standardKey, customStandards, auditInfo, privacySettings, auditTypeOptions,
        processes, activeProcessId, activeProcess,
        auditSites, auditTeam, auditPlanConfig, auditSchedule,
        evidence, matrixData, evidenceTags,
        selectedClauses, knowledgeBase, knowledgeFileName,
        analysisResult, selectedFindings, finalReportText,
        currentJobId
    ]);

    return (
        <AuditContext.Provider value={contextValue}>
            {children}
        </AuditContext.Provider>
    );
};

export const useAudit = () => {
    const context = useContext(AuditContext);
    if (!context) throw new Error("useAudit must be used within AuditProvider");
    return context;
};

import React, { useState, useEffect } from 'react';
import { Modal, Icon } from '../UI';
import { useAudit } from '../../contexts/AuditContext';
import { useUI } from '../../contexts/UIContext';
import { JobStore } from '../../services/jobStore';
import { AuditJob } from '../../types';

interface JobManagerModalProps {
    isOpen: boolean;
    onClose: () => void;
}

export const JobManagerModal: React.FC<JobManagerModalProps> = ({ isOpen, onClose }) => {
    const { auditInfo, standardKey, saveCurrentJob, loadJob, currentJobId, resetSession, standards } = useAudit();
    const { showToast } = useUI();

    const [activeTab, setActiveTab] = useState<'list' | 'save'>('list');
    const [jobs, setJobs] = useState<AuditJob[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [saveName, setSaveName] = useState("");

    // Initialize Save Name based on context
    useEffect(() => {
        if (isOpen) {
            loadJobsList();

            const stdName = standards[standardKey]?.name || "ISO";
            let shortStd = stdName.split(' ')[0];
            if(stdName.includes("27001")) shortStd = "ISO27k";
            else if(stdName.includes("9001")) shortStd = "ISO9k";

            const client = auditInfo.company || "NewClient";
            const date = new Date().toISOString().split('T')[0];
            setSaveName(`${client} - ${shortStd} - ${date}`);

            // If already in a job, default to List view, else if new session with data, maybe prompt save
            if (!currentJobId && auditInfo.company) {
                setActiveTab('save');
            } else {
                setActiveTab('list');
            }
        }
    }, [isOpen, auditInfo.company, standardKey]);

    const loadJobsList = async () => {
        setIsLoading(true);
        try {
            const list = await JobStore.getAllJobs();
            setJobs(list);
        } catch (e) {
            console.error(e);
            showToast("Failed to load jobs.");
        } finally {
            setIsLoading(false);
        }
    };

    const handleSave = async () => {
        if (!saveName.trim()) return showToast("Please enter a job name.");
        setIsLoading(true);
        try {
            await saveCurrentJob(saveName.trim());
            showToast("Job Saved Successfully!");
            await loadJobsList();
            setActiveTab('list');
        } catch (e) {
            console.error(e);
            showToast("Failed to save job.");
        } finally {
            setIsLoading(false);
        }
    };

    const handleLoad = (job: AuditJob) => {
        if (confirm(`Load "${job.name}"? Unsaved progress in current session will be lost.`)) {
            loadJob(job);
            showToast(`Loaded: ${job.name}`);
            onClose();
        }
    };

    const handleDelete = async (e: React.MouseEvent, id: string) => {
        e.stopPropagation();
        if (confirm("Permanently delete this job record?")) {
            await JobStore.deleteJob(id);
            setJobs(prev => prev.filter(j => j.id !== id));
            showToast("Job deleted.");
        }
    };

    const handleNewJob = () => {
        if (confirm("Start a fresh audit session?")) {
            resetSession();
            showToast("New Session Started.");
            onClose();
        }
    };

    return (
        <Modal isOpen={isOpen} title="Audit Job Manager" onClose={onClose}>
            <div className="flex flex-col h-[60vh]">

                {/* Tabs */}
                <div className="flex gap-2 mb-4 border-b border-gray-100 dark:border-slate-800 pb-2">
                    <button 
                        onClick={() => setActiveTab('list')}
                        className={`px-4 py-2 text-xs font-bold rounded-lg transition-colors flex items-center gap-2 ${activeTab === 'list' ? 'bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-300' : 'text-slate-500 hover:bg-gray-50 dark:hover:bg-slate-800'}`}
                    >
                        <Icon name="LayoutList" size={14}/> My Audits ({jobs.length})
                    </button>
                    <button 
                        onClick={() => setActiveTab('save')}
                        className={`px-4 py-2 text-xs font-bold rounded-lg transition-colors flex items-center gap-2 ${activeTab === 'save' ? 'bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-300' : 'text-slate-500 hover:bg-gray-50 dark:hover:bg-slate-800'}`}
                    >
                        <Icon name="Save" size={14}/> Save Current Job
                    </button>
                </div>

                {/* Content */}
                <div className="flex-1 overflow-y-auto custom-scrollbar relative p-1">
                    {activeTab === 'list' && (
                        <div className="space-y-3">
                            {/* Create New Action */}
                            <div 
                                onClick={handleNewJob}
                                className="flex items-center gap-4 p-4 rounded-xl border border-dashed border-gray-300 dark:border-slate-700 cursor-pointer hover:bg-gray-50 dark:hover:bg-slate-800/50 transition-colors group"
                            >
                                <div className="w-10 h-10 rounded-full bg-slate-100 dark:bg-slate-800 flex items-center justify-center text-slate-400 group-hover:text-indigo-500 transition-colors">
                                    <Icon name="Plus" size={20}/>
                                </div>
                                <div>
                                    <h4 className="text-sm font-bold text-slate-700 dark:text-slate-300">Start New Audit</h4>
                                    <p className="text-xs text-slate-500">Reset workspace for a new client</p>
                                </div>
                            </div>

                            {/* Job List */}
                            {isLoading ? (
                                <div className="text-center py-10 text-slate-400 flex flex-col items-center">
                                    <Icon name="Loader" className="animate-spin mb-2"/>
                                    <span className="text-xs">Loading saved jobs...</span>
                                </div>
                            ) : jobs.length === 0 ? (
                                <div className="text-center py-10 text-slate-400 text-xs italic">
                                    No saved jobs found.
                                </div>
                            ) : (
                                jobs.map(job => (
                                    <div 
                                        key={job.id}
                                        onClick={() => handleLoad(job)}
                                        className={`group relative p-4 rounded-xl border cursor-pointer transition-all hover:shadow-md ${currentJobId === job.id ? 'bg-emerald-50 dark:bg-emerald-900/10 border-emerald-200 dark:border-emerald-800 ring-1 ring-emerald-500/20' : 'bg-white dark:bg-slate-900 border-gray-100 dark:border-slate-800 hover:border-indigo-200 dark:hover:border-indigo-900'}`}
                                    >
                                        <div className="flex justify-between items-start mb-2">
                                            <div>
                                                <h4 className="text-sm font-bold text-slate-800 dark:text-slate-200 flex items-center gap-2">
                                                    {job.name}
                                                    {currentJobId === job.id && <span className="text-[9px] bg-emerald-100 text-emerald-700 px-1.5 py-0.5 rounded font-black uppercase">Active</span>}
                                                </h4>
                                                <p className="text-xs text-slate-500 dark:text-slate-400 mt-0.5">
                                                    {new Date(job.lastModified).toLocaleString()}
                                                </p>
                                            </div>
                                            <button 
                                                onClick={(e) => handleDelete(e, job.id)}
                                                className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-full transition-colors opacity-0 group-hover:opacity-100"
                                            >
                                                <Icon name="Trash2" size={16}/>
                                            </button>
                                        </div>

                                        <div className="flex items-center gap-4 text-[10px] text-slate-500 dark:text-slate-400 font-medium bg-gray-50 dark:bg-slate-950/50 p-2 rounded-lg">
                                            <span className="flex items-center gap-1"><Icon name="Building" size={12}/> {job.thumbnailStats.company}</span>
                                            <span className="flex items-center gap-1"><Icon name="Book" size={12}/> {job.thumbnailStats.standard}</span>
                                            <span className="flex items-center gap-1"><Icon name="Wand2" size={12}/> {job.thumbnailStats.findingsCount} Findings</span>
                                        </div>

                                        {/* Progress Bar */}
                                        <div className="mt-3 flex items-center gap-2">
                                            <div className="flex-1 h-1.5 bg-gray-100 dark:bg-slate-800 rounded-full overflow-hidden">
                                                <div className="h-full bg-indigo-500 rounded-full" style={{ width: `${job.thumbnailStats.progress}%` }}></div>
                                            </div>
                                            <span className="text-[9px] font-bold text-indigo-600 dark:text-indigo-400">{job.thumbnailStats.progress}%</span>
                                        </div>
                                    </div>
                                ))
                            )}
                        </div>
                    )}

                    {activeTab === 'save' && (
                        <div className="space-y-4 p-4 bg-gray-50 dark:bg-slate-900/50 rounded-2xl border border-gray-100 dark:border-slate-800">
                            <div>
                                <label className="text-xs font-bold text-slate-500 uppercase block mb-2">Job Name</label>
                                <input 
                                    className="w-full p-3 bg-white dark:bg-slate-950 border border-gray-200 dark:border-slate-700 rounded-xl text-sm font-bold text-slate-800 dark:text-white outline-none focus:border-indigo-500 focus:ring-2 focus:ring-indigo-500/20"
                                    value={saveName}
                                    onChange={e => setSaveName(e.target.value)}
                                    placeholder="e.g. Acme Corp - ISO 9001 - Oct 2025"
                                />
                            </div>

                            <div className="p-4 bg-white dark:bg-slate-900 rounded-xl border border-dashed border-gray-200 dark:border-slate-700">
                                <h5 className="text-xs font-bold text-slate-600 dark:text-slate-400 mb-2">Current Session Summary</h5>
                                <ul className="space-y-2 text-xs text-slate-500 dark:text-slate-400">
                                    <li className="flex justify-between"><span>Client:</span> <span className="font-bold">{auditInfo.company || "N/A"}</span></li>
                                    <li className="flex justify-between"><span>Standard:</span> <span className="font-bold">{standards[standardKey]?.name || "N/A"}</span></li>
                                    <li className="flex justify-between"><span>Findings:</span> <span className="font-bold">{auditInfo.company ? "Ready to save" : "Start audit first"}</span></li>
                                </ul>
                            </div>

                            <button 
                                onClick={handleSave}
                                disabled={isLoading || !saveName.trim()}
                                className="w-full py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold text-sm shadow-lg shadow-indigo-500/30 transition-all active:scale-95 disabled:opacity-70 disabled:cursor-not-allowed flex items-center justify-center gap-2"
                            >
                                {isLoading ? <Icon name="Loader" className="animate-spin"/> : <Icon name="Save"/>}
                                {currentJobId ? "Update Existing Job" : "Save New Job"}
                            </button>
                        </div>
                    )}
                </div>
            </div>
        </Modal>
    );
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';

interface UIContextType {
    isDarkMode: boolean;
    toggleDarkMode: () => void;
    fontSizeScale: number;
    setFontSizeScale: React.Dispatch<React.SetStateAction<number>>;
    isSidebarOpen: boolean;
    setSidebarOpen: (isOpen: boolean) => void;
    sidebarWidth: number;
    setSidebarWidth: (width: number) => void;

    // Modal State Managers
    modals: {
        settings: boolean;
        about: boolean;
        integrity: boolean;
        recall: boolean;
        addStandard: boolean;
        jobs: boolean; // Added
    };
    toggleModal: (modal: keyof UIContextType['modals'], state?: boolean) => void;

    // Toast
    toastMsg: string | null;
    showToast: (msg: string) => void;
}

const UIContext = createContext<UIContextType | undefined>(undefined);

export const UIProvider = ({ children }: React.PropsWithChildren<{}>) => {
    // Theme
    const [isDarkMode, setIsDarkMode] = useState(true);
    useEffect(() => {
        if (isDarkMode) document.documentElement.classList.add('dark');
        else document.documentElement.classList.remove('dark');
    }, [isDarkMode]);

    // Font
    const [fontSizeScale, setFontSizeScale] = useState(1.0);
    useEffect(() => {
        document.documentElement.style.setProperty('--font-scale', fontSizeScale.toString());
    }, [fontSizeScale]);

    // Layout
    const [isSidebarOpen, setSidebarOpen] = useState(true);
    const [sidebarWidth, setSidebarWidth] = useState(420);

    // Modals
    const [modals, setModals] = useState({
        settings: false,
        about: false,
        integrity: false,
        recall: false,
        addStandard: false,
        jobs: false // Added
    });

    const toggleModal = (modal: keyof typeof modals, state?: boolean) => {
        setModals(prev => ({ ...prev, [modal]: state ?? !prev[modal] }));
    };

    // Toast
    const [toastMsg, setToastMsg] = useState<string | null>(null);
    const showToast = (msg: string) => setToastMsg(msg);

    return (
        <UIContext.Provider value={{
            isDarkMode,
            toggleDarkMode: () => setIsDarkMode(prev => !prev),
            fontSizeScale,
            setFontSizeScale,
            isSidebarOpen,
            setSidebarOpen,
            sidebarWidth,
            setSidebarWidth,
            modals,
            toggleModal,
            toastMsg,
            showToast
        }}>
            {children}
        </UIContext.Provider>
    );
};

export const useUI = () => {
    const context = useContext(UIContext);
    if (!context) throw new Error("useUI must be used within UIProvider");
    return context;
};

